const bridge = window.AppHubBridge
const ctx = bridge.getContext() // app_slug, launch_token, publisher_api_base, app_version, …
const display = bridge.getDisplayUser() // chỉ UI — không dùng cho auth
await bridge.requestPermission('desktop.message')
await bridge.sendDesktopMessage({
  type: 'banner',
  title: 'Xin chào',
  body: 'Chào ' + (display?.name ?? ''),
  duration_ms: 5000
})
